import { getUsername, type AuthUser } from "wasp/auth";
import { logout } from "wasp/client/auth";
import { Link, useNavigate } from "react-router";
import { useEffect } from "react";
import "./Main.css";

export function AdminPage({ user }: { user: AuthUser }) {
  const navigate = useNavigate();

  useEffect(() => {
    if ((user as any).role !== 'ADMIN') {
      navigate("/");
    }
  }, [user, navigate]);

  if ((user as any).role !== 'ADMIN') {
    return null;
  }

  const username = getUsername(user as any);

  return (
    <main className="container">
      <h2 className="title">Admin Panel</h2>
      <p className="content">
        Welcome, Admin {username}!
      </p>
      <div className="buttons">
        <Link className="button button-filled" to="/">
          Back to Main Page
        </Link>
        <button className="button button-outlined" onClick={logout}>
          Logout
        </button>
      </div>
    </main>
  );
}

